export default App

import type { AgentSession, AgentSessionEvent, AgentSessionRuntime } from '@earendil-works/pi-coding-agent'

process.on('uncaughtException', (err: Error) => {
  process.parentPort?.postMessage({ channel: 'error', error: `Uncaught: ${err.message}` })
})

process.on('unhandledRejection', (reason: unknown) => {
  const msg = reason instanceof Error ? reason.message : String(reason)
  process.parentPort?.postMessage({ channel: 'error', error: `Unhandled rejection: ${msg}` })
})

interface WorkerInit {
  cwd: string
  sessionPath?: string
}

interface WorkerCommand {
  id?: string
  type: string
  [key: string]: unknown
}

let session: AgentSession | null = null
let runtime: AgentSessionRuntime | null = null
let sessionManager: import('@earendil-works/pi-coding-agent').SessionManager | null = null
let unsubscribe: (() => void) | null = null
let pi: typeof import('@earendil-works/pi-coding-agent') | null = null

function send(msg: Record<string, unknown>): void {
  process.parentPort?.postMessage(msg)
}

function forwardEvent(event: AgentSessionEvent): void {
  send({ channel: 'event', data: event })
}

async function bindSession(): Promise<void> {
  unsubscribe?.()
  if (!session) return

  await session.bindExtensions({})

  unsubscribe = session.subscribe((event) => {
    forwardEvent(event)

    if (event.type === 'agent_end') {
      send({ channel: 'agent_end' })
    }
  })
}

async function init(data: WorkerInit): Promise<void> {
  pi = await import('@earendil-works/pi-coding-agent')
  const agentDir = pi.getAgentDir()

  const createRuntime: pi.CreateAgentSessionRuntimeFactory = async ({ cwd, sessionManager: sm, sessionStartEvent }) => {
    sessionManager = sm
    const services = await pi!.createAgentSessionServices({ cwd, agentDir })
    return {
      ...(await pi!.createAgentSessionFromServices({
        services,
        sessionManager: sm,
        sessionStartEvent,
      })),
      services,
      diagnostics: services.diagnostics,
    }
  }

  let sm: pi.SessionManager
  if (data.sessionPath) {
    sm = pi.SessionManager.open(data.sessionPath)
  } else {
    sm = pi.SessionManager.continueRecent(data.cwd)
  }

  runtime = await pi.createAgentSessionRuntime(createRuntime, {
    cwd: data.cwd,
    agentDir,
    sessionManager: sm,
  })

  session = runtime.session
  await bindSession()

  send({ channel: 'connected', data: { sessionFile: session.sessionFile, sessionId: session.sessionId } })
}

async function handleCommand(cmd: WorkerCommand): Promise<void> {
  if (!session || !runtime || !pi) {
    send({ channel: 'response', id: cmd.id, success: false, error: 'Session not initialized' })
    return
  }

  try {
    switch (cmd.type) {
      case 'prompt': {
        await session.prompt(cmd.message as string, {
          images: cmd.images as pi.ImageContent[] | undefined,
          streamingBehavior: cmd.streamingBehavior as 'steer' | 'followUp' | undefined,
        })
        send({ channel: 'response', id: cmd.id, command: 'prompt', success: true })
        break
      }

      case 'steer': {
        await session.steer(cmd.message as string, cmd.images as pi.ImageContent[] | undefined)
        send({ channel: 'response', id: cmd.id, command: 'steer', success: true })
        break
      }

      case 'follow_up': {
        await session.followUp(cmd.message as string, cmd.images as pi.ImageContent[] | undefined)
        send({ channel: 'response', id: cmd.id, command: 'follow_up', success: true })
        break
      }

      case 'abort': {
        await session.abort()
        send({ channel: 'response', id: cmd.id, command: 'abort', success: true })
        break
      }

      case 'get_state': {
        send({
          channel: 'response',
          id: cmd.id,
          command: 'get_state',
          success: true,
          data: {
            sessionFile: session.sessionFile,
            sessionId: session.sessionId,
            sessionName: session.sessionName,
            isStreaming: session.isStreaming,
            isCompacting: session.isCompacting,
            thinkingLevel: session.thinkingLevel,
            messageCount: session.messages.length,
          },
        })
        break
      }

      case 'get_messages': {
        let messages = session.messages
        if (messages.length === 0 && sessionManager) {
          try {
            const entries = sessionManager.getEntries()
            const messageEntries = entries.filter((e) => e.type === 'message' && (e as Record<string, unknown>).message)
            messages = messageEntries.map((e) => {
              const entry = e as Record<string, unknown>
              const msg = { ...(entry.message as Record<string, unknown>) }
              if (!msg.id && typeof entry.id === 'string') {
                msg.id = entry.id
              }
              return msg
            }) as unknown as AgentSession['messages']
          } catch {
            // getEntries failed — return empty messages
          }
        }
        send({
          channel: 'response',
          id: cmd.id,
          command: 'get_messages',
          success: true,
          data: { messages },
        })
        break
      }

      case 'get_fork_messages': {
        const messages = session.getUserMessagesForForking()
        send({
          channel: 'response',
          id: cmd.id,
          command: 'get_fork_messages',
          success: true,
          data: { messages },
        })
        break
      }

      case 'set_session_name': {
        session.setSessionName(cmd.name as string)
        send({ channel: 'response', id: cmd.id, command: 'set_session_name', success: true })
        break
      }

      case 'new_session': {
        const result = await runtime.newSession({
          parentSession: cmd.parentSession as string | undefined,
        })
        if (!result.cancelled) {
          session = runtime.session
          await bindSession()
        }
        send({ channel: 'response', id: cmd.id, command: 'new_session', success: true, data: result })
        break
      }

      case 'switch_session': {
        const result = await runtime.switchSession(cmd.sessionPath as string)
        if (!result.cancelled) {
          session = runtime.session
          await bindSession()
        }
        send({ channel: 'response', id: cmd.id, command: 'switch_session', success: true, data: result })
        break
      }

      case 'fork': {
        const result = await runtime.fork(cmd.entryId as string)
        if (!result.cancelled) {
          session = runtime.session
          await bindSession()
        }
        send({ channel: 'response', id: cmd.id, command: 'fork', success: true, data: { text: result.selectedText ?? '', cancelled: result.cancelled } })
        break
      }

      case 'compact': {
        const result = await session.compact(cmd.customInstructions as string | undefined)
        send({ channel: 'response', id: cmd.id, command: 'compact', success: true, data: result })
        break
      }

      case 'send_extension_ui_response': {
        send({ channel: 'response', id: cmd.id, command: 'send_extension_ui_response', success: true })
        break
      }

      default:
        send({ channel: 'response', id: cmd.id, command: cmd.type, success: false, error: `Unknown command: ${cmd.type}` })
    }
  } catch (err: unknown) {
    send({
      channel: 'response',
      id: cmd.id,
      command: cmd.type,
      success: false,
      error: err instanceof Error ? err.message : String(err),
    })
  }
}

process.parentPort.on('message', (event: Electron.ParentPortMessageEvent) => {
  const msg = event.data as WorkerCommand | { type: 'init'; data: WorkerInit }
  if (msg.type === 'init') {
    init((msg as { data: WorkerInit }).data).catch((err: Error) => {
      console.error('[PiWorker] Init failed:', err.message)
      console.error('[PiWorker] Stack:', err.stack)
      send({ channel: 'error', error: `Init failed: ${err.message}` })
    })
    return
  }

  handleCommand(msg as WorkerCommand).catch((err: Error) => {
    send({ channel: 'error', error: err.message })
  })
})

import { utilityProcess } from 'electron'
import workerPath from './pi-worker?modulePath'
import { resolve, join } from 'path'
import { existsSync, mkdirSync, symlinkSync, lstatSync } from 'fs'
import { randomUUID } from 'crypto'
import { EventEmitter } from 'events'

const LINKED_FILES = ['auth.json', 'models.json', 'settings.json']
const LINKED_DIRS = ['tools', 'prompts', 'themes', 'extensions']

interface PendingCommand {
  resolve: (value: unknown) => void
  reject: (reason: Error) => void
  timer: ReturnType<typeof setTimeout>
}

const COMMAND_TIMEOUT_MS = 60_000

interface UtilityChild {
  on(event: 'message', listener: (msg: Record<string, unknown>) => void): UtilityChild
  on(event: 'exit', listener: (code: number | null) => void): UtilityChild
  postMessage(message: unknown): void
  kill(): void
  pid: number | undefined
}

export class PiSDKBridge extends EventEmitter {
  private child: UtilityChild | null = null
  private pendingCommands = new Map<string, PendingCommand>()
  private _isConnected = false
  private _sessionFilePath: string | null = null

  get isConnected(): boolean {
    return this._isConnected && this.child !== null
  }

  get sessionFilePath(): string | null {
    return this._sessionFilePath
  }

  async start(cwd: string, sessionPath?: string): Promise<void> {
    if (this._isConnected) {
      return
    }

    if (this.child) {
      if (this._isConnected) return
      await new Promise<void>((resolve, reject) => {
        const timeout = setTimeout(() => {
          reject(new Error('Timed out waiting for existing process to connect'))
        }, 30_000)
        this.once('connected', () => { clearTimeout(timeout); resolve() })
        this.once('error', (err: Error) => { clearTimeout(timeout); reject(err) })
      })
      return
    }

    const resolvedCwd = resolve(cwd)
    const localAgentDir = join(resolvedCwd, '.xi')
    if (!existsSync(localAgentDir)) {
      mkdirSync(localAgentDir, { recursive: true })
    }
    process.env.PI_CODING_AGENT_DIR = localAgentDir
    this.linkGlobalAgentConfig(localAgentDir)

    const child = utilityProcess.fork(workerPath, [], {
      serviceName: 'pi-sdk',
      stdio: 'pipe',
      env: { ...process.env },
    }) as unknown as UtilityChild

    this.child = child

    child.on('message', (msg: Record<string, unknown>) => {
      this.handleChildMessage(msg)
    })

    child.on('exit', (code: number | null) => {
      console.error('[PiSDKBridge] Process exited with code:', code)
      this._isConnected = false
      this.child = null
      this.rejectAllPending(`Process exited with code ${code}`)
      this.emit('disconnected')
    })

    child.postMessage({ type: 'init', data: { cwd, sessionPath } })

    await new Promise<void>((resolve, reject) => {
      const timeout = setTimeout(() => {
        reject(new Error('Pi SDK process did not respond within 30s'))
      }, 30_000)

      const onConnected = (): void => {
        clearTimeout(timeout)
        resolve()
      }

      const onError = (err: Error): void => {
        clearTimeout(timeout)
        reject(err)
      }

      this.once('connected', onConnected)
      this.once('error', onError)
    })
  }

  sendCommand(command: Record<string, unknown>): void {
    if (!this.child) {
      this.emit('error', new Error('Process not running'))
      return
    }
    this.child.postMessage(command)
  }

  async sendRpcCommand(command: Record<string, unknown>): Promise<unknown> {
    return new Promise((resolve, reject) => {
      if (!this.child) {
        reject(new Error('Process not running'))
        return
      }

      const id = randomUUID()
      const timer = setTimeout(() => {
        this.pendingCommands.delete(id)
        reject(new Error(`SDK command timed out: ${command.type}`))
      }, COMMAND_TIMEOUT_MS)

      this.pendingCommands.set(id, { resolve, reject, timer })
      this.child.postMessage({ ...command, id })
    })
  }

  sendExtensionUIResponse(response: Record<string, unknown>): void {
    this.sendCommand(response)
  }

  async stop(): Promise<void> {
    if (!this.child) return

    this.rejectAllPending('Process stopping')

    this.child.kill()
    this.child = null
    this._isConnected = false
  }

  private linkGlobalAgentConfig(localAgentDir: string): void {
    const globalAgentDir = join(
      process.env.HOME ?? process.env.USERPROFILE ?? '~',
      '.pi',
      'agent'
    )

    for (const file of LINKED_FILES) {
      const source = join(globalAgentDir, file)
      const target = join(localAgentDir, file)
      if (existsSync(source) && !existsSync(target)) {
        try { symlinkSync(source, target) } catch {}
      }
    }

    for (const dir of LINKED_DIRS) {
      const source = join(globalAgentDir, dir)
      const target = join(localAgentDir, dir)
      if (existsSync(source) && !lstatSync(source).isSymbolicLink() && !existsSync(target)) {
        try { symlinkSync(source, target) } catch {}
      }
    }
  }

  private handleChildMessage(msg: Record<string, unknown>): void {
    const channel = msg.channel as string

    switch (channel) {
      case 'connected': {
        this._isConnected = true
        const data = msg.data as Record<string, unknown> | undefined
        if (data?.sessionFile && typeof data.sessionFile === 'string') {
          this._sessionFilePath = data.sessionFile
        }
        this.emit('connected')
        break
      }

      case 'event': {
        this.emit('event', msg.data)
        break
      }

      case 'response': {
        const id = msg.id as string | undefined
        if (id) {
          const pending = this.pendingCommands.get(id)
          if (pending) {
            clearTimeout(pending.timer)
            this.pendingCommands.delete(id)
            if (msg.success) {
              pending.resolve(msg.data)
            } else {
              pending.reject(new Error(typeof msg.error === 'string' ? msg.error : 'SDK command failed'))
            }
          }
        }
        this.emit('response', msg)
        break
      }

      case 'error': {
        this.emit('error', new Error(typeof msg.error === 'string' ? msg.error : 'Unknown worker error'))
        break
      }

      case 'agent_end': {
        break
      }

      default:
        this.emit('event', msg)
    }
  }

  private rejectAllPending(reason: string): void {
    for (const [, pending] of this.pendingCommands) {
      clearTimeout(pending.timer)
      pending.reject(new Error(reason))
    }
    this.pendingCommands.clear()
  }
}

import { useState, useEffect, useCallback, useRef } from 'react'
import type { ChatMessage, ContentBlock } from '../types/message'
import type {
  AgentSessionEvent,
  MessageUpdateEvent,
  ToolExecutionEndEvent,
  PiImageContent,
  PiUserMessage,
  PiAssistantMessage,
  PiToolResultMessage,
  PiContentBlock,
} from '../types/pi-events'
import type { ForkPoint } from '../types/session'

export interface TokenUsage {
  inputTokens: number
  outputTokens: number
  cacheReadTokens: number
  cacheWriteTokens: number
  totalTokens: number
  totalCost: number
  contextWindowSize: number
}

function inferContextWindow(model: string): number {
  if (!model) return 200000
  const m = model.toLowerCase()
  if (m.includes('gpt-4o') || m.includes('gpt-4-turbo')) return 128000
  if (m.includes('claude')) return 200000
  return 200000
}

interface UsePiRpcReturn {
  messages: ChatMessage[]
  isConnected: boolean
  isStreaming: boolean
  streamingMessageId: string | null
  sendPrompt: (text: string, images?: { data: string; mimeType: string }[]) => void
  abort: () => void
  pendingUiRequests: Array<{ id: string; method: string; [key: string]: unknown }>
  respondToUiRequest: (requestId: string, response: Record<string, unknown>) => void
  clearMessages: () => void
  loadHistory: () => Promise<void>
  forkPoints: ForkPoint[]
  loadForkPoints: (sessionPath: string) => Promise<void>
  onAgentEnd: (() => void) | null
  setOnAgentEnd: (cb: (() => void) | null) => void
  tokenUsage: TokenUsage
}

export function usePiRpc(): UsePiRpcReturn {
  const [messages, setMessages] = useState<ChatMessage[]>([])
  const [isConnected, setIsConnected] = useState(false)
  const [isStreaming, setIsStreaming] = useState(false)
  const [pendingUiRequests, setPendingUiRequests] = useState<Array<{ id: string; method: string; [key: string]: unknown }>>([])
  const [tokenUsage, setTokenUsage] = useState<TokenUsage>({
    inputTokens: 0,
    outputTokens: 0,
    cacheReadTokens: 0,
    cacheWriteTokens: 0,
    totalTokens: 0,
    totalCost: 0,
    contextWindowSize: 200000,
  })

  const currentAssistantId = useRef<string | null>(null)
  const currentContentBlocks = useRef<Map<number, ContentBlock>>(new Map())
  const toolCallArgsBuffer = useRef<Map<number, string>>(new Map())
  const pendingToolCallArgs = useRef<Map<string, Record<string, unknown>>>(new Map())

  const updateContentBlock = useCallback(
    (contentIndex: number, updater: (block: ContentBlock) => ContentBlock) => {
      const existing = currentContentBlocks.current.get(contentIndex)
      if (existing) {
        currentContentBlocks.current.set(contentIndex, updater(existing))
      }
    },
    [],
  )

  // RAF-throttled sync to avoid flickering on every text_delta
  const rafIdRef = useRef<number | null>(null)
  const syncContentBlocksToMessage = useCallback(() => {
    if (!currentAssistantId.current) return
    // Always schedule at most one RAF frame
    if (rafIdRef.current !== null) return
    rafIdRef.current = requestAnimationFrame(() => {
      rafIdRef.current = null
      if (!currentAssistantId.current) return
      const blocks = Array.from(currentContentBlocks.current.values())
      const assistantId = currentAssistantId.current
      setMessages((prev) =>
        prev.map((msg) => {
          if (msg.id !== assistantId) return msg
          return { ...msg, blocks: [...blocks] }
        }),
      )
    })
  }, [])

  // Force-flush any pending RAF sync (used at message/agent end)
  const flushSync = useCallback(() => {
    if (rafIdRef.current !== null) {
      cancelAnimationFrame(rafIdRef.current)
      rafIdRef.current = null
    }
    if (!currentAssistantId.current) return
    const blocks = Array.from(currentContentBlocks.current.values())
    const assistantId = currentAssistantId.current
    setMessages((prev) =>
      prev.map((msg) => {
        if (msg.id !== assistantId) return msg
        return { ...msg, blocks: [...blocks] }
      }),
    )
  }, [])

  const finalizeCurrentAssistant = useCallback(() => {
    if (!currentAssistantId.current) return
    flushSync()
  }, [flushSync])

  const handleEvent = useCallback(
    (event: AgentSessionEvent) => {
      switch (event.type) {
        case 'agent_start':
          setIsStreaming(true)
          break

        case 'agent_end':
          setIsStreaming(false)
          flushSync()
          currentAssistantId.current = null
          currentContentBlocks.current.clear()
          toolCallArgsBuffer.current.clear()
          onAgentEndRef.current?.()
          break

        case 'message_start': {
          const msg = event.message
          if (msg.role === 'user') {
            const userMsg = msg as PiUserMessage
            const userContent =
              typeof userMsg.content === 'string'
                ? userMsg.content
                : userMsg.content
                    .filter((c): c is { type: 'text'; text: string } => c.type === 'text')
                    .map((c) => c.text)
                    .join('')

            const userChatMsg: ChatMessage = {
              id: crypto.randomUUID(),
              role: 'user',
              blocks: [{ type: 'text', content: userContent }],
              timestamp: userMsg.timestamp,
            }
            setMessages((prev) => [...prev, userChatMsg])
          } else if (msg.role === 'assistant') {
            const assistantMsg = msg as PiAssistantMessage
            const assistantId = crypto.randomUUID()
            currentAssistantId.current = assistantId
            currentContentBlocks.current.clear()
            toolCallArgsBuffer.current.clear()

            const chatMsg: ChatMessage = {
              id: assistantId,
              role: 'assistant',
              blocks: [],
              timestamp: assistantMsg.timestamp,
            }
            setMessages((prev) => [...prev, chatMsg])
          }
          break
        }

        case 'message_update': {
          const updateEvent = event as MessageUpdateEvent
          const ame = updateEvent.assistantMessageEvent

          if (!currentAssistantId.current) break

          switch (ame.type) {
            case 'text_start':
              currentContentBlocks.current.set(ame.contentIndex, { type: 'text', content: '' })
              break

            case 'text_delta':
              updateContentBlock(ame.contentIndex, (block) => {
                if (block.type === 'text') {
                  return { ...block, content: block.content + ame.delta }
                }
                return block
              })
              break

            case 'text_end':
              updateContentBlock(ame.contentIndex, (block) => {
                if (block.type === 'text') {
                  return { ...block, content: ame.content }
                }
                return block
              })
              break

            case 'thinking_start':
              currentContentBlocks.current.set(ame.contentIndex, { type: 'text', content: '💭 ' })
              break

            case 'thinking_delta':
              updateContentBlock(ame.contentIndex, (block) => {
                if (block.type === 'text') {
                  return { ...block, content: block.content + ame.delta }
                }
                return block
              })
              break

            case 'thinking_end':
              updateContentBlock(ame.contentIndex, (block) => {
                if (block.type === 'text') {
                  return { ...block, content: '💭 ' + ame.content }
                }
                return block
              })
              break

            case 'toolcall_start':
              currentContentBlocks.current.set(ame.contentIndex, {
                type: 'tool_call',
                toolName: '',
                args: {},
                status: 'running',
              })
              toolCallArgsBuffer.current.set(ame.contentIndex, '')
              break

            case 'toolcall_delta': {
              const existing = toolCallArgsBuffer.current.get(ame.contentIndex) ?? ''
              toolCallArgsBuffer.current.set(ame.contentIndex, existing + ame.delta)
              break
            }

            case 'toolcall_end': {
              const argsStr = toolCallArgsBuffer.current.get(ame.contentIndex) ?? '{}'
              let parsedArgs: Record<string, unknown>
              try {
                parsedArgs = JSON.parse(argsStr)
              } catch {
                parsedArgs = { _raw: argsStr }
              }
              currentContentBlocks.current.set(ame.contentIndex, {
                type: 'tool_call',
                toolName: ame.toolCall.name,
                args: parsedArgs,
                status: 'running',
              })
              pendingToolCallArgs.current.set(ame.toolCall.id, parsedArgs)
              toolCallArgsBuffer.current.delete(ame.contentIndex)
              // toolcall_end is an important structural change, flush immediately
              flushSync()
              break
            }

            case 'done': {
              const msg = ame.message
              if (msg.usage) {
                setTokenUsage({
                  inputTokens: msg.usage.input,
                  outputTokens: msg.usage.output,
                  cacheReadTokens: msg.usage.cacheRead,
                  cacheWriteTokens: msg.usage.cacheWrite,
                  totalTokens: msg.usage.input + msg.usage.output,
                  totalCost: msg.usage.cost.total,
                  contextWindowSize: inferContextWindow(msg.responseModel),
                })
              }
              break
            }
            case 'error':
              break
          }

          if (ame.type !== 'toolcall_end') {
            syncContentBlocksToMessage()
          }
          break
        }

        case 'message_end': {
          const msg = event.message
          if (msg.role === 'toolResult') {
            const toolResultMsg = msg as PiToolResultMessage
            const extraBlocks: ContentBlock[] = []

            for (const content of toolResultMsg.content) {
              if (content.type === 'text') {
                extraBlocks.push({ type: 'text', content: content.text })
              } else if (content.type === 'image') {
                const img = content as PiImageContent
                extraBlocks.push({
                  type: 'image',
                  src: `data:${img.mimeType};base64,${img.data}`,
                  alt: 'Screenshot',
                })
              }
            }

            if (extraBlocks.length > 0 && currentAssistantId.current) {
              setMessages((prev) =>
                prev.map((m) => {
                  if (m.id !== currentAssistantId.current) return m
                  return { ...m, blocks: [...m.blocks, ...extraBlocks] }
                }),
              )
            }
          }
          if (msg.role === 'assistant') {
            const assistantMsg = msg as PiAssistantMessage
            if (assistantMsg.usage) {
              setTokenUsage({
                inputTokens: assistantMsg.usage.input,
                outputTokens: assistantMsg.usage.output,
                cacheReadTokens: assistantMsg.usage.cacheRead,
                cacheWriteTokens: assistantMsg.usage.cacheWrite,
                totalTokens: assistantMsg.usage.input + assistantMsg.usage.output,
                totalCost: assistantMsg.usage.cost.total,
                contextWindowSize: inferContextWindow(assistantMsg.responseModel),
              })
            }
          }
          break
        }

        case 'tool_execution_start':
          setMessages((prev) =>
            prev.map((msg) => {
              if (msg.id !== currentAssistantId.current) return msg
              return {
                ...msg,
                blocks: msg.blocks.map((block) => {
                  if (
                    block.type === 'tool_call' &&
                    block.toolName === event.toolName &&
                    block.status === 'pending'
                  ) {
                    return { ...block, status: 'running' as const }
                  }
                  return block
                }),
              }
            }),
          )
          break

        case 'tool_execution_end': {
          const toolEvent = event as ToolExecutionEndEvent
          const toolArgs = pendingToolCallArgs.current.get(toolEvent.toolCallId)
          pendingToolCallArgs.current.delete(toolEvent.toolCallId)

          const extraBlocks: ContentBlock[] = []

          const hasImageContent = toolEvent.result?.content?.some(
            (c: Record<string, unknown>) => c.type === 'image'
          )

          if (hasImageContent) {
            for (const c of toolEvent.result.content as Array<Record<string, unknown>>) {
              if (c.type === 'text' && typeof c.text === 'string') {
                extraBlocks.push({ type: 'text', content: c.text })
              } else if (c.type === 'image') {
                const img = c as unknown as PiImageContent
                extraBlocks.push({
                  type: 'image',
                  src: `data:${img.mimeType};base64,${img.data}`,
                  alt: `Result from ${toolEvent.toolName}`,
                })
              }
            }
          }

          if (
            toolEvent.toolName === 'write' &&
            toolArgs &&
            typeof toolArgs.path === 'string' &&
            toolArgs.path.endsWith('.html') &&
            typeof toolArgs.content === 'string'
          ) {
            extraBlocks.push({
              type: 'html',
              content: toolArgs.content,
              title: toolArgs.path.split('/').pop(),
            })
          }

          if (extraBlocks.length > 0) {
            setMessages((prev) =>
              prev.map((msg) => {
                if (msg.id !== currentAssistantId.current) return msg
                return {
                  ...msg,
                  blocks: [
                    ...msg.blocks.map((block) => {
                      if (block.type === 'tool_call' && block.status === 'running') {
                        return { ...block, status: 'completed' as const }
                      }
                      return block
                    }),
                    ...extraBlocks,
                  ],
                }
              }),
            )
          } else {
            setMessages((prev) =>
              prev.map((msg) => {
                if (msg.id !== currentAssistantId.current) return msg
                return {
                  ...msg,
                  blocks: msg.blocks.map((block) => {
                    if (block.type === 'tool_call' && block.status === 'running') {
                      return { ...block, status: 'completed' as const }
                    }
                    return block
                  }),
                }
              }),
            )
          }
          break
        }

        default:
          break
      }
    },
    [updateContentBlock, syncContentBlocksToMessage, finalizeCurrentAssistant],
  )

  useEffect(() => {
    const cleanup = window.api.onStateChanged((state) => {
      setIsConnected(state.connected)
    })

    window.api.getState().then((state) => {
      setIsConnected(state.connected)
    })

    return cleanup
  }, [])

  useEffect(() => {
    const cleanup = window.api.onEvent((rawEvent) => {
      handleEvent(rawEvent as AgentSessionEvent)
    })
    return cleanup
  }, [handleEvent])

  useEffect(() => {
    const cleanup = window.api.onExtensionUiRequest((data) => {
      const req = data as { id: string; method: string; [key: string]: unknown }
      if (req.method === 'notify') {
        return
      }
      if (req.method === 'setStatus' || req.method === 'setWidget' || req.method === 'setTitle' || req.method === 'set_editor_text') {
        return
      }
      setPendingUiRequests(prev => [...prev, req])
    })
    return cleanup
  }, [])

  const respondToUiRequest = useCallback((requestId: string, response: Record<string, unknown>) => {
    window.api.sendExtensionUIResponse({ type: 'extension_ui_response', id: requestId, ...response })
    setPendingUiRequests(prev => prev.filter(r => r.id !== requestId))
  }, [])

  const sendPrompt = useCallback(
    (text: string, images?: { data: string; mimeType: string }[]) => {
      const command: Record<string, unknown> = {
        type: 'prompt',
        message: text,
        id: crypto.randomUUID(),
      }
      if (images && images.length > 0) {
        command.images = images.map((img) => ({
          type: 'image' as const,
          data: img.data,
          mimeType: img.mimeType,
        }))
      }
      window.api.sendCommand(command)
    },
    [],
  )

  const abort = useCallback(() => {
    window.api.sendCommand({ type: 'abort' })
  }, [])

  const clearMessages = useCallback(() => {
    setMessages([])
    setForkPoints([])
    setTokenUsage({
      inputTokens: 0,
      outputTokens: 0,
      cacheReadTokens: 0,
      cacheWriteTokens: 0,
      totalTokens: 0,
      totalCost: 0,
      contextWindowSize: 200000,
    })
    currentAssistantId.current = null
    currentContentBlocks.current.clear()
    toolCallArgsBuffer.current.clear()
    pendingToolCallArgs.current.clear()
  }, [])

  const [forkPoints, setForkPoints] = useState<ForkPoint[]>([])
  const onAgentEndRef = useRef<(() => void) | null>(null)

  const setOnAgentEnd = useCallback((cb: (() => void) | null) => {
    onAgentEndRef.current = cb
  }, [])

  const loadForkPoints = useCallback(async (sessionPath: string) => {
    type ExtendedApiWithForkPoints = typeof window.api & { getForkPoints: (path: string) => Promise<ForkPoint[]> }
    const apiWithFp = window.api as ExtendedApiWithForkPoints
    try {
      const points = await apiWithFp.getForkPoints(sessionPath)
      setForkPoints(points)
    } catch {
      setForkPoints([])
    }
  }, [])

  const loadHistory = useCallback(async () => {
    type ExtendedApiWithMessages = typeof window.api & { getMessages: () => Promise<unknown[]> }
    const api = window.api as ExtendedApiWithMessages

    let piMessages: unknown[]
    try {
      piMessages = await api.getMessages()
    } catch {
      return
    }

    if (!Array.isArray(piMessages) || piMessages.length === 0) {
      clearMessages()
      return
    }

    const chatMessages: ChatMessage[] = []

    for (const raw of piMessages) {
      const msg = raw as Record<string, unknown>
      const piEntryId = typeof msg.id === 'string' ? msg.id : undefined
      if (msg.role === 'user') {
        const content = typeof msg.content === 'string'
          ? msg.content
          : Array.isArray(msg.content)
            ? (msg.content as PiContentBlock[])
                .filter((c): c is { type: 'text'; text: string } => c.type === 'text')
                .map((c) => c.text)
                .join('')
            : ''
        chatMessages.push({
          id: crypto.randomUUID(),
          role: 'user',
          blocks: [{ type: 'text', content }],
          timestamp: typeof msg.timestamp === 'number' ? msg.timestamp : Date.now(),
          piEntryId,
        })
      } else if (msg.role === 'assistant') {
        const blocks: ContentBlock[] = []
        const content = msg.content as PiContentBlock[]
        if (Array.isArray(content)) {
          for (const c of content) {
            if (c.type === 'text') {
              blocks.push({ type: 'text', content: c.text })
            } else if (c.type === 'thinking') {
              blocks.push({ type: 'text', content: '\u{1F4AD} ' + c.thinking })
            } else if (c.type === 'toolCall') {
              blocks.push({
                type: 'tool_call',
                toolName: c.name,
                args: c.arguments,
                status: 'completed',
              })
            }
          }
        }
        chatMessages.push({
          id: crypto.randomUUID(),
          role: 'assistant',
          blocks,
          timestamp: typeof msg.timestamp === 'number' ? msg.timestamp : Date.now(),
          piEntryId,
        })
      } else if (msg.role === 'toolResult') {
        const lastAssistant = chatMessages.findLast((m) => m.role === 'assistant')
        if (lastAssistant) {
          const content = msg.content as PiContentBlock[]
          if (Array.isArray(content)) {
            for (const c of content) {
              if (c.type === 'text') {
                lastAssistant.blocks.push({ type: 'text', content: c.text })
              } else if (c.type === 'image') {
                const img = c as PiImageContent
                lastAssistant.blocks.push({
                  type: 'image',
                  src: `data:${img.mimeType};base64,${img.data}`,
                  alt: `Result from ${msg.toolName as string}`,
                })
              }
            }
          }
        }
      }
    }

    // Extract token usage from last assistant message in history
    let restoredUsage: TokenUsage | null = null
    for (let i = piMessages.length - 1; i >= 0; i--) {
      const msg = piMessages[i] as Record<string, unknown>
      if (msg.role === 'assistant') {
        const usage = msg.usage as { input: number; output: number; cacheRead: number; cacheWrite: number; totalTokens: number; cost: { input: number; output: number; cacheRead: number; cacheWrite: number; total: number } } | undefined
        const responseModel = typeof msg.responseModel === 'string' ? msg.responseModel : ''
        if (usage) {
          restoredUsage = {
            inputTokens: usage.input,
            outputTokens: usage.output,
            cacheReadTokens: usage.cacheRead,
            cacheWriteTokens: usage.cacheWrite,
            totalTokens: usage.input + usage.output,
            totalCost: usage.cost.total,
            contextWindowSize: inferContextWindow(responseModel),
          }
        }
        break
      }
    }

    clearMessages()
    setMessages(chatMessages)
    // Apply token usage after clearMessages to avoid being overwritten
    if (restoredUsage) {
      setTokenUsage(restoredUsage)
    }
  }, [clearMessages])

  const streamingMessageId = isStreaming ? currentAssistantId.current : null

  return { messages, isConnected, isStreaming, streamingMessageId, sendPrompt, abort, pendingUiRequests, respondToUiRequest, clearMessages, loadHistory, forkPoints, loadForkPoints, onAgentEnd: onAgentEndRef.current, setOnAgentEnd, tokenUsage }
}

import { app, BrowserWindow, ipcMain, nativeTheme } from 'electron'
import { join } from 'path'
import { PiSDKBridge } from './pi-sdk-bridge'
import * as sessionService from './session-service'
import type { SessionInfo, ForkableMessage, ForkPoint } from '../renderer/src/types/session'

let mainWindow: BrowserWindow | null = null
let piBridge: PiSDKBridge | null = null
let initialSessionPath: string | undefined

function createWindow(): void {
  mainWindow = new BrowserWindow({
    width: 1200,
    height: 800,
    backgroundColor: '#ffffff',
    titleBarStyle: 'hiddenInset',
    show: false,
    webPreferences: {
      preload: join(__dirname, '../preload/index.js'),
      sandbox: false
    }
  })

  mainWindow.on('ready-to-show', () => {
    mainWindow?.show()
  })

  mainWindow.on('closed', () => {
    mainWindow = null
  })

  if (process.env.ELECTRON_RENDERER_URL) {
    mainWindow.loadURL(process.env.ELECTRON_RENDERER_URL)
  } else {
    mainWindow.loadFile(join(__dirname, '../renderer/index.html'))
  }
}

function broadcastToRenderers(channel: string, data: unknown): void {
  BrowserWindow.getAllWindows().forEach((win) => {
    if (!win.isDestroyed() && !win.webContents.isDestroyed()) {
      try {
        win.webContents.send(channel, data)
      } catch {}
    }
  })
}

function initPiBridge(sessionPath?: string): void {
  piBridge = new PiSDKBridge()
  initialSessionPath = sessionPath

  piBridge.on('event', (data: unknown) => {
    // In SDK mode, extension_ui_request arrives as a regular event
    if (typeof data === 'object' && data !== null) {
      const obj = data as Record<string, unknown>
      if (obj.type === 'extension_ui_request') {
        broadcastToRenderers('pi:extensionUiRequest', data)
        return
      }
    }
    broadcastToRenderers('pi:event', data)
  })

  piBridge.on('response', (data: unknown) => {
    broadcastToRenderers('pi:response', data)
  })

  piBridge.on('connected', () => {
    broadcastToRenderers('pi:stateChanged', { connected: true })
  })

  piBridge.on('disconnected', () => {
    broadcastToRenderers('pi:stateChanged', { connected: false })
  })

  piBridge.on('error', (err: Error) => {
    console.error('[PiSDKBridge]', err.message)
  })
}

function registerIpcHandlers(): void {
  ipcMain.handle('pi:sendCommand', (_event, command: Record<string, unknown>) => {
    if (!piBridge?.isConnected) return { ok: false, error: 'Pi not connected' }
    piBridge.sendCommand(command)
    return { ok: true }
  })

  ipcMain.handle('pi:sendExtensionUIResponse', (_event, response: Record<string, unknown>) => {
    if (!piBridge?.isConnected) return { ok: false, error: 'Pi not connected' }
    piBridge.sendExtensionUIResponse(response)
    return { ok: true }
  })

  ipcMain.handle('pi:getState', () => {
    return { connected: piBridge?.isConnected ?? false }
  })

  ipcMain.handle('pi:start', async () => {
    if (!piBridge) {
      let mainSession = sessionService.findMainSession(process.cwd())
      if (mainSession && !mainSession.name) {
        sessionService.nameSession(mainSession.filePath, 'main')
        mainSession = { ...mainSession, name: 'main' }
      }
      initPiBridge(mainSession?.filePath)
    }
    try {
      await piBridge!.start(process.cwd(), initialSessionPath)
      const mainSession = sessionService.findMainSession(process.cwd())
      if (!mainSession || !mainSession.name) {
        try {
          await piBridge!.sendRpcCommand({ type: 'set_session_name', name: 'main' })
        } catch {}
        const sessionPath = piBridge!.sessionFilePath
        if (sessionPath) {
          sessionService.nameSession(sessionPath, 'main', process.cwd())
        }
      }
      return { ok: true }
    } catch (err: unknown) {
      return { ok: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('pi:stop', async () => {
    try {
      await piBridge?.stop()
      return { ok: true }
    } catch (err: unknown) {
      return { ok: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('session:listSessions', async () => {
    let currentPath: string | undefined
    try {
      const data = (await piBridge!.sendRpcCommand({ type: 'get_state' })) as Record<string, unknown>
      if (typeof data.sessionFile === 'string') currentPath = data.sessionFile
    } catch {
      currentPath = undefined
    }
    return sessionService.listSessions(currentPath)
  })

  ipcMain.handle('session:getForkMessages', async () => {
    try {
      const data = (await piBridge!.sendRpcCommand({ type: 'get_fork_messages' })) as {
        messages?: ForkableMessage[]
      }
      return data.messages ?? []
    } catch {
      return []
    }
  })

  ipcMain.handle('session:forkAtEntry', async (_event, entryId: string, name?: string) => {
    let parentPath: string | null = null
    try {
      const preState = (await piBridge!.sendRpcCommand({ type: 'get_state' })) as Record<string, unknown>
      parentPath = typeof preState.sessionFile === 'string' ? preState.sessionFile : null
    } catch {}

    try {
      const data = (await piBridge!.sendRpcCommand({ type: 'fork', entryId })) as Record<string, unknown>

      if (name) {
        try {
          await piBridge!.sendRpcCommand({ type: 'set_session_name', name })
        } catch {}
        try {
          const postState = (await piBridge!.sendRpcCommand({ type: 'get_state' })) as Record<string, unknown>
          const childPath = typeof postState.sessionFile === 'string' ? postState.sessionFile : null
          if (childPath) {
            sessionService.nameSession(childPath, name)
          }
        } catch {}
      }

      if (parentPath) {
        sessionService.addForkPoint(parentPath, entryId, name ?? '')
      }

      return { success: true, text: typeof data.text === 'string' ? data.text : undefined }
    } catch (err: unknown) {
      return { success: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('session:switchSession', async (_event, sessionPath: string) => {
    try {
      await piBridge!.sendRpcCommand({ type: 'switch_session', sessionPath })
      return { success: true }
    } catch (err: unknown) {
      return { success: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('session:newSession', async (_event, parentSessionPath?: string) => {
    try {
      const command: Record<string, unknown> = { type: 'new_session' }
      if (parentSessionPath) {
        command.parentSession = parentSessionPath
      }
      await piBridge!.sendRpcCommand(command)
      return { success: true }
    } catch (err: unknown) {
      return { success: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('session:renameSession', async (_event, name: string) => {
    try {
      await piBridge!.sendRpcCommand({ type: 'set_session_name', name })
    } catch {}

    try {
      const data = (await piBridge!.sendRpcCommand({ type: 'get_state' })) as Record<string, unknown>
      const sessionPath = typeof data.sessionFile === 'string' ? data.sessionFile : null
      if (sessionPath) {
        sessionService.nameSession(sessionPath, name)
      }
    } catch {}

    return { success: true }
  })

  ipcMain.handle('session:getCurrentSession', async () => {
    try {
      const data = (await piBridge!.sendRpcCommand({ type: 'get_state' })) as Record<string, unknown>
      const sessionPath = typeof data.sessionFile === 'string' ? data.sessionFile : null
      if (!sessionPath) return null

      const result = sessionService.listSessions()
      for (const project of result.projects) {
        const found = project.allSessions.find((s) => s.filePath === sessionPath)
        if (found) return found
      }
      return null
    } catch {
      return null
    }
  })

  ipcMain.handle('session:refreshSessions', async () => {
    let currentPath: string | undefined
    try {
      const data = (await piBridge!.sendRpcCommand({ type: 'get_state' })) as Record<string, unknown>
      if (typeof data.sessionFile === 'string') currentPath = data.sessionFile
    } catch {
      currentPath = undefined
    }
    return sessionService.listSessions(currentPath)
  })

  ipcMain.handle('session:getMessages', async () => {
    try {
      const data = (await piBridge!.sendRpcCommand({ type: 'get_messages' })) as { messages?: unknown[] }
      return data.messages ?? []
    } catch {
      return []
    }
  })

  ipcMain.handle('session:deleteSession', async (_event, sessionPath: string) => {
    try {
      const stateData = (await piBridge!.sendRpcCommand({ type: 'get_state' })) as Record<string, unknown>
      const currentPath = typeof stateData.sessionFile === 'string' ? stateData.sessionFile : null
      if (currentPath === sessionPath) {
        return { success: false, error: 'Cannot delete the active session' }
      }
    } catch {}

    const result = sessionService.deleteSession(sessionPath)
    if (result) {
      return { success: true }
    }
    return { success: false, error: 'Failed to delete session' }
  })

  ipcMain.handle('session:getForkPoints', async (_event, sessionPath: string) => {
    return sessionService.getForkPoints(sessionPath)
  })

  ipcMain.handle('session:clearSession', async () => {
    try {
      const stateData = (await piBridge!.sendRpcCommand({ type: 'get_state' })) as Record<string, unknown>
      const oldPath = typeof stateData.sessionFile === 'string' ? stateData.sessionFile : null
      const sessionName = typeof stateData.sessionName === 'string' ? stateData.sessionName : null

      if (!oldPath) {
        return { success: false, error: 'No active session to clear' }
      }

      await piBridge!.sendRpcCommand({ type: 'new_session' })

      const newName = sessionName ?? 'main'
      try {
        await piBridge!.sendRpcCommand({ type: 'set_session_name', name: newName })
      } catch {}

      const postState = (await piBridge!.sendRpcCommand({ type: 'get_state' })) as Record<string, unknown>
      const newPath = typeof postState.sessionFile === 'string' ? postState.sessionFile : null
      if (newPath) {
        sessionService.nameSession(newPath, newName)
      }

      sessionService.deleteSession(oldPath)

      return { success: true }
    } catch (err: unknown) {
      return { success: false, error: err instanceof Error ? err.message : String(err) }
    }
  })
}

app.whenReady().then(() => {
  nativeTheme.themeSource = 'light'
  let mainSession = sessionService.findMainSession(process.cwd())

  if (mainSession && !mainSession.name) {
    sessionService.nameSession(mainSession.filePath, 'main')
    mainSession = { ...mainSession, name: 'main' }
  }

  initPiBridge(mainSession?.filePath)
  registerIpcHandlers()
  createWindow()

  app.on('activate', () => {
    if (BrowserWindow.getAllWindows().length === 0) {
      createWindow()
    }
  })
})

app.on('window-all-closed', () => {
  if (process.platform !== 'darwin') {
    app.quit()
  }
})

app.on('before-quit', () => {
  piBridge?.stop().catch((err: Error) => {
    console.error('[PiSDKBridge] Error during shutdown:', err.message)
  })
})

import { useState, useCallback, useEffect, useRef } from 'react'
import type { SessionListResult, SessionInfo, SessionTreeNode } from '../types/session'

interface SessionSidebarProps {
  sessions: SessionListResult | null
  currentSession: SessionInfo | null
  onSwitchSession: (sessionPath: string) => void
  onNewSession: (name: string) => void
  onRenameSession: (name: string) => void
  onDeleteSession: (sessionPath: string) => Promise<boolean>
  isCollapsed: boolean
  onToggleCollapse: () => void
}

function formatRelativeTime(isoTimestamp: string): string {
  const now = Date.now()
  const then = new Date(isoTimestamp).getTime()
  const diffMs = now - then
  const diffMin = Math.floor(diffMs / 60000)
  const diffHr = Math.floor(diffMs / 3600000)
  const diffDay = Math.floor(diffMs / 86400000)

  if (diffMin < 1) return 'just now'
  if (diffMin < 60) return `${diffMin}m ago`
  if (diffHr < 24) return `${diffHr}h ago`
  if (diffDay < 30) return `${diffDay}d ago`
  return new Date(isoTimestamp).toLocaleDateString()
}

function getDisplayName(session: SessionInfo): string {
  if (session.name) return session.name
  const d = new Date(session.createdAt)
  const month = d.toLocaleString('en', { month: 'short' })
  const day = d.getDate()
  const hh = String(d.getHours()).padStart(2, '0')
  const mm = String(d.getMinutes()).padStart(2, '0')
  return `${month} ${day} ${hh}:${mm}`
}

const SLOT_W = 16
const LINE_LEFT = 7

function isDescendantOf(node: SessionTreeNode, sessionPath: string | null): boolean {
  if (!sessionPath) return false
  if (node.session.filePath === sessionPath) return true
  return node.children.some((child) => isDescendantOf(child, sessionPath))
}

function GuideLine({ color }: { color: string }) {
  return (
    <div
      className="flex-shrink-0 relative pointer-events-none"
      style={{ width: SLOT_W, alignSelf: 'stretch' }}
    >
      <div
        className="absolute"
        style={{
          left: LINE_LEFT,
          top: 0,
          bottom: 0,
          width: 1,
          backgroundColor: color,
        }}
      />
    </div>
  )
}

function GuideBranch({ color, branchColor, bottomColor }: { color: string; branchColor?: string; bottomColor?: string }) {
  const brColor = branchColor ?? color
  const btColor = bottomColor ?? color
  return (
    <div
      className="flex-shrink-0 relative pointer-events-none"
      style={{ width: SLOT_W, alignSelf: 'stretch' }}
    >
      {/* 上半段竖线 + 圆角 + 水平分支：用 border 绘制，与 GuideElbow 同样的圆角效果 */}
      <div
        className="absolute"
        style={{
          left: LINE_LEFT,
          top: 0,
          height: '50%',
          width: SLOT_W - LINE_LEFT - 1,
          borderLeft: `1px solid ${color}`,
          borderBottom: `1px solid ${brColor}`,
          borderBottomLeftRadius: 4,
        }}
      />
      {/* 下半段竖线：从50%到底部，后续兄弟是否在 active path 上 */}
      <div
        className="absolute"
        style={{
          left: LINE_LEFT,
          top: '50%',
          bottom: 0,
          width: 1,
          backgroundColor: btColor,
        }}
      />
    </div>
  )
}

function GuideElbow({ color }: { color: string }) {
  return (
    <div
      className="flex-shrink-0 relative pointer-events-none"
      style={{ width: SLOT_W, alignSelf: 'stretch' }}
    >
      <div
        className="absolute"
        style={{
          left: LINE_LEFT,
          top: 0,
          height: '50%',
          width: SLOT_W - LINE_LEFT - 1,
          borderLeft: `1px solid ${color}`,
          borderBottom: `1px solid ${color}`,
          borderBottomLeftRadius: 4,
        }}
      />
    </div>
  )
}

function GuideSlot() {
  return (
    <div
      className="flex-shrink-0"
      style={{ width: SLOT_W, alignSelf: 'stretch' }}
    />
  )
}

function DotSlot({
  active,
  hasChildren,
  isExpanded,
  gutterActive,
}: {
  active: boolean
  hasChildren: boolean
  isExpanded: boolean
  gutterActive: boolean
}) {
  return (
    <div
      className="flex-shrink-0 flex flex-col items-center relative"
      style={{ width: SLOT_W, alignSelf: 'stretch' }}
    >
      <div className="flex items-center justify-center h-6">
        <div
          className={
            active
              ? 'w-2.5 h-2.5 rounded-full bg-blue-500 border-2 border-blue-500 flex-shrink-0'
              : 'w-2.5 h-2.5 rounded-full bg-white border-2 border-gray-300 group-hover:border-blue-500 flex-shrink-0'
          }
        />
      </div>
      {hasChildren && isExpanded && (
        <div
          className="absolute"
          style={{
            left: LINE_LEFT,
            top: 24,
            bottom: 0,
            width: 1,
            backgroundColor: gutterActive ? '#3b82f6' : '#e5e7eb',
          }}
        />
      )}
    </div>
  )
}

function SessionNode({
  node,
  ancestorLines,
  currentSessionPath,
  isOnActivePath,
  onSwitch,
  onRename,
  onDelete,
  onContextMenu,
  triggerRenamePath,
  onRenameTriggered,
}: {
  node: SessionTreeNode
  ancestorLines: { hasLine: boolean; color: string; branchColor?: string; bottomColor?: string }[]
  currentSessionPath: string | null
  isOnActivePath: boolean
  onSwitch: (path: string) => void
  onRename: (name: string) => void
  onDelete: (path: string) => Promise<boolean>
  onContextMenu: (e: React.MouseEvent, session: SessionInfo) => void
  triggerRenamePath: string | null
  onRenameTriggered: () => void
}): React.ReactElement {
  const [isExpanded, setIsExpanded] = useState(true)
  const [isRenaming, setIsRenaming] = useState(false)
  const [renameValue, setRenameValue] = useState(getDisplayName(node.session))
  const [confirmDelete, setConfirmDelete] = useState(false)
  const isActive = currentSessionPath === node.session.filePath
  const hasChildren = node.children.length > 0

  useEffect(() => {
    if (triggerRenamePath === node.session.filePath) {
      setIsRenaming(true)
      setRenameValue(getDisplayName(node.session))
      onRenameTriggered()
    }
  }, [triggerRenamePath, node.session.filePath, onRenameTriggered])

  const handleDoubleClick = useCallback(() => {
    setIsRenaming(true)
    setRenameValue(getDisplayName(node.session))
  }, [node.session])

  const handleRenameSubmit = useCallback(() => {
    const trimmed = renameValue.trim()
    if (trimmed && trimmed !== getDisplayName(node.session)) {
      onRename(trimmed)
    }
    setIsRenaming(false)
  }, [renameValue, node.session, onRename])

  const hasChildOnActivePath = node.children.some(
    (child) =>
      currentSessionPath === child.session.filePath ||
      isDescendantOf(child, currentSessionPath)
  )

  const gutterActive = hasChildOnActivePath

  const renderGuides = () => {
    if (ancestorLines.length === 0) return null
    return ancestorLines.map((entry, i) => {
      const isConnector = i === ancestorLines.length - 1
      if (isConnector) {
        if (entry.hasLine) {
          return <GuideBranch key={i} color={entry.color} branchColor={entry.branchColor} bottomColor={entry.bottomColor} />
        }
        return <GuideElbow key={i} color={entry.color} />
      }
      if (entry.hasLine) {
        return <GuideLine key={i} color={entry.bottomColor ?? entry.color} />
      }
      return <GuideSlot key={i} />
    })
  }

  return (
    <div>
      <div
        className={`group flex items-center rounded cursor-pointer transition-colors ${
          isActive
            ? 'bg-gray-100 text-gray-900'
            : 'text-gray-600 hover:bg-gray-100/60 hover:text-gray-800'
        }`}
        onClick={() => onSwitch(node.session.filePath)}
        onDoubleClick={handleDoubleClick}
        onContextMenu={(e) => onContextMenu(e, node.session)}
      >
        {renderGuides()}
        <DotSlot
          active={isOnActivePath || isActive || node.session.isMain}
          hasChildren={hasChildren}
          isExpanded={isExpanded}
          gutterActive={gutterActive}
        />
        <div className="flex-1 flex items-center gap-1 py-1.5 pr-2 min-w-0">
          {isRenaming ? (
            <input
              autoFocus
              value={renameValue}
              onChange={(e) => setRenameValue(e.target.value)}
              onBlur={handleRenameSubmit}
              onKeyDown={(e) => {
                if (e.key === 'Enter') handleRenameSubmit()
                if (e.key === 'Escape') setIsRenaming(false)
              }}
              onClick={(e) => e.stopPropagation()}
              className="flex-1 min-w-0 bg-gray-100 rounded px-1 py-0.5 text-xs text-gray-900 outline-none border border-gray-300 focus:border-blue-500"
            />
          ) : (
            <span className="flex-1 truncate text-xs">
              {getDisplayName(node.session)}
            </span>
          )}

          <span className="flex-shrink-0 text-[10px] text-gray-400 opacity-0 group-hover:opacity-100 transition-opacity">
            {formatRelativeTime(node.session.createdAt)}
          </span>

          {hasChildren && (
            <button
              onClick={(e) => {
                e.stopPropagation()
                setIsExpanded(!isExpanded)
              }}
              className="flex-shrink-0 rounded px-0.5 py-0.5 text-gray-400 hover:text-gray-600 hover:bg-gray-100 opacity-0 group-hover:opacity-100 transition-colors"
              title={isExpanded ? 'Collapse' : 'Expand'}
            >
              <svg
                className={`w-3 h-3 transition-transform ${isExpanded ? 'rotate-90' : ''}`}
                fill="currentColor"
                viewBox="0 0 20 20"
              >
                <path
                  fillRule="evenodd"
                  d="M7.21 14.77a.75.75 0 01.02-1.06L11.168 10 7.23 6.29a.75.75 0 111.04-1.08l4.5 4.25a.75.75 0 010 1.08l-4.5 4.25a.75.75 0 01-1.06-.02z"
                  clipRule="evenodd"
                />
              </svg>
            </button>
          )}

          {node.session.parentSessionPath && (
            <button
              onClick={(e) => {
                e.stopPropagation()
                onSwitch(node.session.parentSessionPath!)
              }}
              className="flex-shrink-0 rounded px-0.5 py-0.5 text-gray-400 hover:text-blue-500 hover:bg-gray-100 opacity-0 group-hover:opacity-100 transition-colors"
              title="Go to parent session"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" />
              </svg>
            </button>
          )}

          {!isActive && !node.session.isMain && (
            <button
              onClick={(e) => {
                e.stopPropagation()
                if (confirmDelete) {
                  onDelete(node.session.filePath)
                  setConfirmDelete(false)
                } else {
                  setConfirmDelete(true)
                }
              }}
              onBlur={() => setConfirmDelete(false)}
              className={`flex-shrink-0 rounded px-1 py-0.5 text-[10px] opacity-0 group-hover:opacity-100 transition-colors ${
                confirmDelete
                  ? 'bg-red-600 text-white opacity-100'
                  : 'text-gray-400 hover:text-red-500 hover:bg-gray-100'
              }`}
            >
              {confirmDelete ? 'Del' : 'x'}
            </button>
          )}
        </div>
      </div>

      {hasChildren && isExpanded && (
        <div>
          {node.children.map((child, i) => {
            const childIsActivePath =
              currentSessionPath === child.session.filePath ||
              isDescendantOf(child, currentSessionPath)
            const laterSiblingOnActivePath = node.children
              .slice(i + 1)
              .some(
                (sibling) =>
                  currentSessionPath === sibling.session.filePath ||
                  isDescendantOf(sibling, currentSessionPath)
              )
            const branchColor = childIsActivePath ? '#3b82f6' : '#e5e7eb'            // 水平分支：当前节点是否 active
            const continuationColor = laterSiblingOnActivePath ? '#3b82f6' : '#e5e7eb' // 下半段竖线：后续兄弟是否 active
            const onPath = childIsActivePath || laterSiblingOnActivePath
            const verticalTopColor = onPath ? '#3b82f6' : '#e5e7eb'                  // 上半段竖线：整条线是否在 active path 上
            const newAncestorLines = [
              ...ancestorLines.map((entry) => ({
                hasLine: entry.hasLine,
                color: entry.color,
                branchColor: entry.branchColor,
                bottomColor: entry.bottomColor,
              })),
              {
                hasLine: i < node.children.length - 1,
                color: verticalTopColor,
                branchColor: branchColor,
                bottomColor: i < node.children.length - 1 ? continuationColor : undefined,
              },
            ]
            return (
              <SessionNode
                key={child.session.filePath}
                node={child}
                ancestorLines={newAncestorLines}
                currentSessionPath={currentSessionPath}
                isOnActivePath={childIsActivePath}
                onSwitch={onSwitch}
                onRename={onRename}
                onDelete={onDelete}
                onContextMenu={onContextMenu}
                triggerRenamePath={triggerRenamePath}
                onRenameTriggered={onRenameTriggered}
              />
            )
          })}
        </div>
      )}
    </div>
  )
}

function SessionSidebar({
  sessions,
  currentSession,
  onSwitchSession,
  onNewSession,
  onRenameSession,
  onDeleteSession,
  isCollapsed,
  onToggleCollapse,
}: SessionSidebarProps): React.ReactElement {
  const [isCreating, setIsCreating] = useState(false)
  const [newSessionName, setNewSessionName] = useState('')
  const [sidebarWidth, setSidebarWidth] = useState(() => {
    const saved = localStorage.getItem('xi-sidebar-width')
    const parsed = saved ? parseInt(saved, 10) : 260
    return Number.isNaN(parsed) ? 260 : Math.min(480, Math.max(180, parsed))
  })
  const [isResizing, setIsResizing] = useState(false)
  const [contextMenu, setContextMenu] = useState<{
    x: number
    y: number
    session: SessionInfo
  } | null>(null)
  const [triggerRenamePath, setTriggerRenamePath] = useState<string | null>(null)

  const sidebarWidthRef = useRef(sidebarWidth)
  sidebarWidthRef.current = sidebarWidth

  const resizeStartRef = useRef<{ startX: number; startWidth: number } | null>(null)

  const projects = sessions?.projects ?? []
  const projectName = projects[0]?.projectPath.split('/').pop() ?? 'Sessions'
  const root = projects[0]?.root ?? null

  const handleCreateSession = useCallback(() => {
    const trimmed = newSessionName.trim()
    if (!trimmed) return
    onNewSession(trimmed)
    setNewSessionName('')
    setIsCreating(false)
  }, [newSessionName, onNewSession])

  const handleContextMenu = useCallback((e: React.MouseEvent, session: SessionInfo) => {
    e.preventDefault()
    e.stopPropagation()
    setContextMenu({ x: e.clientX, y: e.clientY, session })
  }, [])

  const handleRenameTriggered = useCallback(() => {
    setTriggerRenamePath(null)
  }, [])

  useEffect(() => {
    if (!contextMenu) return

    const handleClick = () => setContextMenu(null)
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setContextMenu(null)
    }

    document.addEventListener('click', handleClick)
    document.addEventListener('keydown', handleKeyDown)

    return () => {
      document.removeEventListener('click', handleClick)
      document.removeEventListener('keydown', handleKeyDown)
    }
  }, [contextMenu])

  useEffect(() => {
    if (!isResizing) return

    const handleMouseMove = (e: MouseEvent) => {
      if (!resizeStartRef.current) return
      const delta = e.clientX - resizeStartRef.current.startX
      const newWidth = Math.min(480, Math.max(180, resizeStartRef.current.startWidth + delta))
      setSidebarWidth(newWidth)
    }

    const handleMouseUp = () => {
      setIsResizing(false)
      resizeStartRef.current = null
      localStorage.setItem('xi-sidebar-width', String(sidebarWidthRef.current))
      document.body.style.cursor = ''
      document.body.style.userSelect = ''
    }

    document.body.style.cursor = 'col-resize'
    document.body.style.userSelect = 'none'
    window.addEventListener('mousemove', handleMouseMove)
    window.addEventListener('mouseup', handleMouseUp)

    return () => {
      window.removeEventListener('mousemove', handleMouseMove)
      window.removeEventListener('mouseup', handleMouseUp)
    }
  }, [isResizing])

  const handleResizeStart = useCallback((e: React.MouseEvent) => {
    e.preventDefault()
    setIsResizing(true)
    resizeStartRef.current = { startX: e.clientX, startWidth: sidebarWidth }
  }, [sidebarWidth])

  if (isCollapsed) {
    return (
      <div className="flex flex-col items-center w-12 bg-gray-50 border-r border-gray-200 pt-10 pb-3">
        <button
          onClick={onToggleCollapse}
          className="rounded p-2 text-gray-400 hover:text-gray-600 hover:bg-gray-100 transition-colors"
          title="Expand sidebar"
        >
          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
            <path strokeLinecap="round" strokeLinejoin="round" d="M13 5l7 7-7 7M5 5l7 7-7 7" />
          </svg>
        </button>
      </div>
    )
  }

  return (
    <div
      className="relative flex flex-col bg-gray-50 border-r border-gray-200 overflow-hidden"
      style={{ width: `${sidebarWidth}px` }}
    >
      <div className="flex items-center justify-between px-3 pt-10 pb-3 border-b border-gray-200">
        <span className="text-xs font-semibold uppercase tracking-wider text-gray-500 truncate">{projectName}</span>
        <div className="flex items-center gap-1 flex-shrink-0">
          <button
            onClick={() => { setIsCreating(true); setNewSessionName('') }}
            className="rounded p-1 text-gray-400 hover:text-gray-600 hover:bg-gray-100 transition-colors"
            title="New session"
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
              <path strokeLinecap="round" strokeLinejoin="round" d="M12 4v16m8-8H4" />
            </svg>
          </button>
          <button
            onClick={onToggleCollapse}
            className="rounded p-1 text-gray-400 hover:text-gray-600 hover:bg-gray-100 transition-colors"
            title="Collapse sidebar"
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
              <path strokeLinecap="round" strokeLinejoin="round" d="M11 19l-7-7 7-7M19 19l-7-7 7-7" />
            </svg>
          </button>
        </div>
      </div>

      {isCreating && (
        <div className="flex items-center gap-1 border-b border-gray-200 px-3 py-2">
          <input
            autoFocus
            value={newSessionName}
            onChange={(e) => setNewSessionName(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter') handleCreateSession()
              if (e.key === 'Escape') setIsCreating(false)
            }}
            placeholder="Session name"
            className="flex-1 min-w-0 rounded border border-gray-300 bg-white px-2 py-1 text-xs text-gray-900 outline-none focus:border-blue-500"
          />
          <button
            onClick={handleCreateSession}
            disabled={!newSessionName.trim()}
            className="rounded bg-blue-600 px-2 py-1 text-xs font-medium text-white hover:bg-blue-500 disabled:opacity-40 disabled:cursor-not-allowed"
          >
            Create
          </button>
        </div>
      )}

      <div className="flex-1 overflow-y-auto py-2">
        {projects.length === 0 || !root ? (
          <div className="px-3 py-6 text-center text-xs text-gray-600">
            No sessions found
          </div>
        ) : (
          <SessionNode
            node={root}
            ancestorLines={[]}
            currentSessionPath={currentSession?.filePath ?? null}
            isOnActivePath={true}
            onSwitch={onSwitchSession}
            onRename={onRenameSession}
            onDelete={onDeleteSession}
            onContextMenu={handleContextMenu}
            triggerRenamePath={triggerRenamePath}
            onRenameTriggered={handleRenameTriggered}
          />
        )}
      </div>

      <div
        className="absolute top-0 right-0 w-1 h-full cursor-col-resize hover:w-1.5 hover:bg-blue-500/30 transition-all z-10"
        onMouseDown={handleResizeStart}
      />

      {contextMenu && (
        <div
          className="fixed z-50 bg-white border border-gray-200 rounded-lg shadow-lg py-1 text-xs min-w-[140px]"
          style={{ left: contextMenu.x, top: contextMenu.y }}
          onClick={(e) => e.stopPropagation()}
        >
          <div
            className="px-3 py-1.5 hover:bg-gray-100 cursor-pointer"
            onClick={() => {
              setTriggerRenamePath(contextMenu.session.filePath)
              setContextMenu(null)
            }}
          >
            Rename
          </div>
          {contextMenu.session.parentSessionPath && (
            <div
              className="px-3 py-1.5 hover:bg-gray-100 cursor-pointer"
              onClick={() => {
                onSwitchSession(contextMenu.session.parentSessionPath!)
                setContextMenu(null)
              }}
            >
              Go to parent
            </div>
          )}
          {contextMenu.session.filePath !== currentSession?.filePath && !contextMenu.session.isMain && (
            <div
              className="px-3 py-1.5 hover:bg-red-50 cursor-pointer text-red-600"
              onClick={() => {
                onDeleteSession(contextMenu.session.filePath)
                setContextMenu(null)
              }}
            >
              Delete
            </div>
          )}
        </div>
      )}
    </div>
  )
}

export default SessionSidebar

