     }
+    // After loading history, always ensure streaming is false
+    // (the session is not actively streaming when we're just loading history)
+    updateStreamingState(false)
   }, [clearMessages])

   // §6.6.2 Rule 2: Sync streaming state from Pi after session transitions.
   // Queries get_state RPC and applies isStreaming. On failure, keeps isStreaming = false
   // (safe default set by clearMessages).
   const syncStreamingState = useCallback(async () => {
     try {
       const state = await (window.api as typeof window.api & { getStreamingState: () => Promise<{ isStreaming: boolean }> }).getStreamingState()
-      setIsStreaming(state.isStreaming)
+      updateStreamingState(state.isStreaming)
     } catch {
       // Keep isStreaming = false (safe default from clearMessages)
+      updateStreamingState(false)
     }
-  }, [])
+  }, [updateStreamingState])

   const streamingMessageId = isStreaming ? currentAssistantId.current : null

   return { messages, isConnected, isStreaming, streamingMessageId, sendPrompt, abort, pendingUiRequests, respondToUiRequest, clearMessages, loadHistory, syncStreamingState, forkPoints, loadForkPoints, onAgentEnd: onAgentEndRef.current, setOnAgentEnd, tokenUsage }

